  // Calculate Tasks per Pillar
  const data = PILLARS.map(pillar => ({
    name: t(pillar.id.toLowerCase() as any) || pillar.label, 
    value: tasks.filter(t => t.pillar === pillar.id && t.completed).length,
    color: pillar.hex // Use explicitly defined hex color
  })).filter(d => d.value > 0);

  const chartData = data.length > 0 ? data : [{ name: t('noData'), value: 1, color: '#333333' }];

  return (
    <div className="h-full overflow-y-auto space-y-6 pb-24 animate-fade-in p-1">

      {/* Welcome Banner */}
      <div className="px-1 mt-2">
        <p className="text-neutral-400 text-sm font-medium">مرحباً بك،</p>
        <h2 className="text-2xl font-black text-white">{playerProfile?.name || 'اللاعب'}</h2>
      </div>

      {/* Top Stats Grid */}
      <div className="grid grid-cols-2 gap-3">
        {/* Level & XP Widget - Circular */}
        <div className="col-span-1 row-span-2">
             <DashboardWidget 
                label={t('level')}
                value={stats.level}
                subValue="Level"
                icon={Trophy}
                iconColor="text-yellow-500"
                progress={{
                    current: stats.currentXp,
                    max: stats.maxXp,
                    colorClass: "bg-game-red"
                }}
                variant="circular"
                borderColor="border-game-red-dim"
            />
        </div>

        {/* Energy Widget */}
        <DashboardWidget 
            label={t('energy')}
            value={stats.energy}
            subValue={`/ ${stats.maxEnergy}`}
            icon={Zap}
            iconColor="text-yellow-400"
            progress={{
                current: stats.energy,
                max: stats.maxEnergy,
                colorClass: "bg-yellow-500"
            }}
        />

        {/* Streak Widget */}
        <div className="grid grid-cols-2 gap-3">
            <DashboardWidget 
                label={t('streak')}
                value={stats.streak}
                icon={Flame}
                iconColor="text-orange-500"
            />
             <DashboardWidget 
