  return (
    <div className="h-full overflow-y-auto flex flex-col items-center justify-center p-6 text-center space-y-6 animate-fade-in pb-20">
      <div className="w-24 h-24 bg-game-red rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(220,38,38,0.5)] mb-4">
