            <p className="text-xs text-red-500 mt-4">ملاحظة: لم يتم العثور على API_KEY. لن تعمل ميزة الذكاء الاصطناعي بشكل كامل.</p>
        )}
    </div>
  );
};

import React from 'react';
import { useSettings } from '../context/SettingsContext';
import { useGame } from '../context/GameContext';
import { useToast } from '../context/ToastContext';
import { Moon, Sun, Globe, Palette, AlertTriangle, Check, RotateCcw, Bell } from 'lucide-react';
import { ThemeColor } from '../types';

export const SettingsScreen: React.FC = () => {
  const { language, themeColor, darkMode, notificationsEnabled, updateSettings, t } = useSettings();
  const { resetProgress } = useGame();
  const { addToast } = useToast();

  const themes: { id: ThemeColor; color: string; label: string }[] = [
    { id: 'red-black', color: '#dc2626', label: 'Red & Black' },
    { id: 'blue-dark', color: '#3b82f6', label: 'Blue & Dark' },
    { id: 'green-matrix', color: '#22c55e', label: 'Matrix Green' },
    { id: 'purple-royal', color: '#a855f7', label: 'Royal Purple' },
  ];

  const handleNotificationToggle = async () => {
    if (!notificationsEnabled) {
      if (!('Notification' in window)) {
        addToast("هذا المتصفح لا يدعم الإشعارات", 'error');
        return;
      }

      const permission = await Notification.requestPermission();
      if (permission === 'granted') {
        updateSettings({ notificationsEnabled: true });
        new Notification("Solo Level", { body: "تم تفعيل الإشعارات بنجاح!" });
        addToast("تم تفعيل الإشعارات", 'success');
      } else {
        addToast("تم رفض الإذن للإشعارات", 'error');
      }
    } else {
      updateSettings({ notificationsEnabled: false });
      addToast("تم إيقاف الإشعارات", 'info');
    }
  };

  return (
    <div className="h-full overflow-y-auto p-6 space-y-8 animate-fade-in pb-24">
      <h2 className="text-3xl font-black text-game-red mb-6">{t('settingsScreen')}</h2>

      {/* Notifications Section */}
      <section className="bg-game-dark border border-neutral-800 rounded-2xl p-4">
        <div className="flex items-center gap-2 mb-4 text-neutral-400">
            <Bell size={18} />
            <h3 className="font-bold text-sm uppercase tracking-widest">الإشعارات</h3>
        </div>
        <button 
            onClick={handleNotificationToggle}
            className="w-full flex items-center justify-between p-4 bg-neutral-900 rounded-xl border border-neutral-800 hover:bg-neutral-800 transition-colors"
        >
            <span className="font-bold">تذكير يومي بالمهام</span>
            <div className={`w-12 h-6 rounded-full p-1 transition-colors ${notificationsEnabled ? 'bg-green-500' : 'bg-neutral-700'}`}>
                <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-transform ${notificationsEnabled ? (language === 'ar' ? '-translate-x-6' : 'translate-x-6') : ''}`} />
            </div>
        </button>
        <p className="text-[10px] text-neutral-600 mt-2">سنرسل لك إشعاراً يومياً لتذكيرك بمهامك إذا نسيت.</p>
      </section>

      {/* Language Section */}
      <section className="bg-game-dark border border-neutral-800 rounded-2xl p-4">
        <div className="flex items-center gap-2 mb-4 text-neutral-400">
            <Globe size={18} />
            <h3 className="font-bold text-sm uppercase tracking-widest">{t('language')}</h3>
        </div>
        <div className="grid grid-cols-2 gap-3">
            <button 
                onClick={() => updateSettings({ language: 'ar' })}
                className={`p-4 rounded-xl font-bold transition-all border ${language === 'ar' ? 'bg-game-red text-white border-game-red' : 'bg-neutral-900 text-neutral-500 border-neutral-800'}`}
            >
                العربية
            </button>
            <button 
                onClick={() => updateSettings({ language: 'en' })}
                className={`p-4 rounded-xl font-bold transition-all border ${language === 'en' ? 'bg-game-red text-white border-game-red' : 'bg-neutral-900 text-neutral-500 border-neutral-800'}`}
