      </section>

      {/* Appearance Section */}
      <section className="bg-game-dark border border-neutral-800 rounded-2xl p-4">
        <div className="flex items-center gap-2 mb-4 text-neutral-400">
            <Palette size={18} />
            <h3 className="font-bold text-sm uppercase tracking-widest">{t('theme')}</h3>
