        >
            <span className="font-bold">{t('darkMode')}</span>
            <div className={`w-12 h-6 rounded-full p-1 transition-colors ${darkMode ? 'bg-game-red' : 'bg-neutral-700'}`}>
                <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-transform ${darkMode ? 'translate-x-0' : (language === 'ar' ? '-translate-x-6' : 'translate-x-6')}`} />
