export const StorageService = {
  // --- Profile ---
  saveProfile: (profile: PlayerProfile) => {
    try {
        localStorage.setItem(PLAYER_KEY, JSON.stringify(profile));
    } catch (e) {
        console.error("Failed to save profile", e);
    }
  },

  loadProfile: (): PlayerProfile | null => {
    try {
        const data = localStorage.getItem(PLAYER_KEY);
        return data ? JSON.parse(data) : null;
    } catch (e) {
        return null;
    }
  },

  // --- Stats ---
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      if (!data) return null;
      const parsed = JSON.parse(data);
      // Migration: Ensure new fields exist
      return { ...defaultStats, ...parsed };
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  // --- Tasks ---
  saveTasks: (tasks: Task[]) => {
    try {
      // CRITICAL FIX: Always create a fresh object with fresh arrays
      const pillarsData: PillarsData = createEmptyPillarsData();

      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });
      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];
      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });

      // Ensure tasks have order property if missing (migration)
      return allTasks.map((t, i) => ({
        ...t,
        order: t.order ?? i
      })).sort((a, b) => a.order - b.order);

    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  // --- History (New) ---
  saveWeeklyHistory: (history: WeeklyHistory[]) => {
    try {
      localStorage.setItem(WEEKLY_HISTORY_KEY, JSON.stringify(history));
    } catch (e) {
      console.error("Failed to save weekly history", e);
    }
  },

  loadWeeklyHistory: (): WeeklyHistory[] => {
    try {
      const data = localStorage.getItem(WEEKLY_HISTORY_KEY);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      return [];
    }
  },

  saveMonthlyHistory: (history: MonthlyHistory[]) => {
    try {
      localStorage.setItem(MONTHLY_HISTORY_KEY, JSON.stringify(history));
    } catch (e) {
      console.error("Failed to save monthly history", e);
    }
  },

  loadMonthlyHistory: (): MonthlyHistory[] => {
    try {
      const data = localStorage.getItem(MONTHLY_HISTORY_KEY);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      return [];
    }
  },

  // --- Settings ---
  saveSettings: (settings: AppSettings) => {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error("Failed to save settings", e);
    }
  },

  loadSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(SETTINGS_KEY);
      return data ? { ...defaultSettings, ...JSON.parse(data) } : defaultSettings;
    } catch (e) {
      return defaultSettings;
    }
  },

  // --- Utility ---
  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
    localStorage.removeItem(SETTINGS_KEY);
    localStorage.removeItem(PLAYER_KEY);
    localStorage.removeItem(WEEKLY_HISTORY_KEY);
    localStorage.removeItem(MONTHLY_HISTORY_KEY);
  },

  initializeNewAccount: (profile: PlayerProfile) => {
    StorageService.saveProfile(profile);
    StorageService.saveStats(defaultStats);
    StorageService.saveTasks([]);
    StorageService.saveSettings(defaultSettings);
    StorageService.saveWeeklyHistory([]);
    StorageService.saveMonthlyHistory([]);
  }
};

import { Task, UserStats, WeeklyHistory, MonthlyHistory, PillarType } from '../types';

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const HistoryEngine = {
  /**
   * Calculates the Rank Score based on the formula:
   * (totalXP * 0.4) + (tasksCompleted * 0.3) + (streakMax * 0.2) + (exerciseConsistency * 0.1)
   */
  calculateRankScore: (xp: number, tasks: number, streak: number, exerciseCount: number): number => {
    // Normalize exercise consistency (assuming 5 times a week is "perfect" for score)
    const exerciseScore = Math.min(exerciseCount * 20, 100); 

    // Simple normalization for others to keep score readable (approx 0-1000 range usually)
    const score = (xp * 0.4) + (tasks * 10 * 0.3) + (streak * 10 * 0.2) + (exerciseScore * 0.1);
    return Math.floor(score);
  },

  /**
   * Creates a Weekly Snapshot from current stats and tasks
   */
  createWeeklySnapshot: (stats: UserStats, tasks: Task[]): WeeklyHistory => {
    const endDate = new Date().toISOString().split('T')[0];
    const startDate = stats.currentWeekStart || endDate;
    const monthId = startDate.substring(0, 7); // YYYY-MM

    // Aggregate Pillar Stats for this week
    // Note: Since we don't have historical task completion dates in the basic task array 
    // (only 'completed' boolean), we rely on the `UserStats` accumulated counters for accuracy.
    // However, to fill `statsSummary`, we will estimate based on completed tasks if explicit counters aren't detailed enough,
    // OR ideally, we should have been tracking pillar counts in stats. 
    // For this implementation, we will count ALL currently completed tasks as the distribution source
    // but scale it to the `weeklyTasksCompleted` count to be proportional.

    const totalCompletedEver = tasks.filter(t => t.completed).length || 1;
    const ratio = stats.weeklyTasksCompleted / totalCompletedEver;

    const getPillarCount = (p: PillarType) => Math.floor(tasks.filter(t => t.pillar === p && t.completed).length * ratio);

    const snapshot: WeeklyHistory = {
        weekId: generateId(),
        monthId: monthId,
        weekIndexInMonth: Math.ceil(new Date(startDate).getDate() / 7), // Approx week of month
        startDate,
        endDate,

        totalXP: stats.weeklyXpAccumulated,
        tasksCompleted: stats.weeklyTasksCompleted,
        streakMax: stats.weeklyMaxStreak,

        statsSummary: {
            learning: getPillarCount('Learning'),
            studying: getPillarCount('Studying'),
            exercise: getPillarCount('Exercise'),
            work: getPillarCount('Work'),
            entertainment: getPillarCount('Entertainment'),
            quran: getPillarCount('Quran'),
        },

        rankScore: HistoryEngine.calculateRankScore(
            stats.weeklyXpAccumulated, 
            stats.weeklyTasksCompleted, 
            stats.weeklyMaxStreak, 
            stats.weeklyExerciseCount
        ),
        createdAt: Date.now()
    };

    return snapshot;
  },

  /**
   * Aggregates 4 weeks into a Monthly Snapshot
   */
  createMonthlySnapshot: (monthId: string, weeks: WeeklyHistory[]): MonthlyHistory => {
    if (weeks.length === 0) throw new Error("No weeks to aggregate");

    const totalXP = weeks.reduce((sum, w) => sum + w.totalXP, 0);
    const totalTasks = weeks.reduce((sum, w) => sum + w.tasksCompleted, 0);
    const rankScores = weeks.map(w => w.rankScore);
    const bestScore = Math.max(...rankScores);
    const worstScore = Math.min(...rankScores);
    const maxStreak = Math.max(...weeks.map(w => w.streakMax));

    // Consistency: (Weeks with score > 100 / Total Weeks) * 100 ? Or based on streak?
    // Let's use: Average Rank Score normalized to a % relative to Best Score
    const consistencyRate = bestScore > 0 
        ? Math.round((weeks.reduce((sum, w) => sum + w.rankScore, 0) / weeks.length) / bestScore * 100) 
        : 0;

    // Determine Rank
    let monthRank = 'Novice';
    if (totalXP > 10000) monthRank = 'Legend';
    else if (totalXP > 5000) monthRank = 'Elite Hunter';
    else if (totalXP > 2000) monthRank = 'Grinder';
    else monthRank = 'Survivor';

    // Aggregate Pillar Stats
    const summary = {
        learning: 0, studying: 0, exercise: 0, work: 0, entertainment: 0, quran: 0
    };
    weeks.forEach(w => {
        summary.learning += w.statsSummary.learning;
        summary.studying += w.statsSummary.studying;
        summary.exercise += w.statsSummary.exercise;
        summary.work += w.statsSummary.work;
        summary.entertainment += w.statsSummary.entertainment;
        summary.quran += w.statsSummary.quran;
    });

    const snapshot: MonthlyHistory = {
        monthId,
        startDate: weeks[0].startDate,
        endDate: weeks[weeks.length - 1].endDate,
        weeksIncluded: weeks.map(w => w.weekId),

        totalXP,
        averageXP: Math.round(totalXP / weeks.length),
        totalTasks,

        bestWeekRankScore: bestScore,
        worstWeekRankScore: worstScore,

        statsSummary: summary,
        streakRecord: maxStreak,
        consistencyRate,
        monthRank,
        createdAt: Date.now()
    };

    return snapshot;
  }
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { GameState, Task, UserStats, PlayerProfile, PillarType, WeeklyHistory, MonthlyHistory } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_RATES, PAGES_PER_JUZ, XP_SCALING_FACTOR, SHADOW_TASKS } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  // New Modal Controls
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();

  // Load from Storage & Silent Days Logic & Time Cycle Check
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);
    if (loadedWeekly) setWeeklyHistory(loadedWeekly);
    if (loadedMonthly) setMonthlyHistory(loadedMonthly);

    if (loadedStats) {
        // Silent Days: Decay calculation
        const lastLoginDate = new Date(loadedStats.lastLoginDate);
        const now = new Date();
        const diffTime = Math.abs(now.getTime() - lastLoginDate.getTime());
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

        let adjustedStats = { ...loadedStats };

        if (diffDays > 0) {
            const decay = diffDays * 2;
            adjustedStats.energy = Math.max(0, adjustedStats.energy - decay);
            adjustedStats.lastLoginDate = getLocalDateString();
        }

        // --- ⏰ TIME CYCLE CHECK (WEEKLY SNAPSHOT) ---
        const weekStart = new Date(adjustedStats.currentWeekStart || now.toISOString());
        const daysSinceWeekStart = Math.floor((now.getTime() - weekStart.getTime()) / (1000 * 60 * 60 * 24));

        if (daysSinceWeekStart >= 7) {
            console.log("⏰ Week Cycle Complete! Generating Snapshot...");

            // 1. Generate Weekly Snapshot
            const newSnapshot = HistoryEngine.createWeeklySnapshot(adjustedStats, loadedTasks || []);
            const updatedWeeklyHistory = [...(loadedWeekly || []), newSnapshot];
            setWeeklyHistory(updatedWeeklyHistory);
            StorageService.saveWeeklyHistory(updatedWeeklyHistory);
            addToast("تم حفظ تقرير الأسبوع بنجاح! 📊", 'info');

            // 2. Check for Monthly Aggregation (Every 4 weeks roughly, or same monthId)
            // Filter weeks that belong to the current monthId and are not yet in a monthly snapshot
            const currentMonthId = newSnapshot.monthId;
            const weeksInThisMonth = updatedWeeklyHistory.filter(w => w.monthId === currentMonthId);

            // If we have 4 (or 5) weeks for this month, lock it.
            // Simplified logic: If we hit 4 weeks, trigger month.
            // Advanced: Check if next week belongs to next month. For now, 4 weeks rule.
            if (weeksInThisMonth.length === 4) {
                 const alreadyExists = (loadedMonthly || []).some(m => m.monthId === currentMonthId);
                 if (!alreadyExists) {
                     const monthSnapshot = HistoryEngine.createMonthlySnapshot(currentMonthId, weeksInThisMonth);
                     const updatedMonthlyHistory = [...(loadedMonthly || []), monthSnapshot];
                     setMonthlyHistory(updatedMonthlyHistory);
                     StorageService.saveMonthlyHistory(updatedMonthlyHistory);
                     addToast("تقرير الشهر جاهز! 🏆", 'level-up');
                 }
            }

            // 3. Reset Weekly Tracking Stats
            adjustedStats.currentWeekStart = getLocalDateString();
            adjustedStats.weeklyXpAccumulated = 0;
            adjustedStats.weeklyTasksCompleted = 0;
            adjustedStats.weeklyMaxStreak = 0;
            adjustedStats.weeklyExerciseCount = 0;
        }

        setStats(adjustedStats);
    }

    setIsLoaded(true);
  }, []);

  // 6️⃣ Shadow Tasks Injection
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        const hasShadowTask = tasks.some(t => t.isShadow && !t.completed);

        if (!hasShadowTask) {
            const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
            const shadowTask: Task = {
                id: generateId(),
                title: `👻 ${randomShadow.title}`,
                description: randomShadow.description,
                pillar: 'Entertainment', // Fallback pillar
                completed: false,
                energyCost: -randomShadow.energyRestore,
                xpReward: 0,
                createdAt: Date.now(),
                order: -1,
                isShadow: true
            };
            setTasks(prev => [shadowTask, ...prev]);
            addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
        }
    }
  }, [stats.energy, isLoaded, playerProfile, tasks]);


  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  useEffect(() => {
    if (!isLoaded || !playerProfile) return;
    regenerateEnergy();
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy,
          xpReward: rates.xp,
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }
      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
  }, []);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;
        // ... (Completion logic simplified for brevity, assume XP handled same as tasks)
        const bonusXP = 500;
        let currentXp = prev.currentXp + bonusXP;
        // ALSO Add to weekly Tracking
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(100 * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }
        if (didLevelUp) setShowLevelUpModal(true);
        else addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated
        };
    });
  }, [addToast]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        return;
    }

    const timeMod = getTimeModifier();
    const rates = PILLAR_RATES[task.pillar];
    const finalEnergyCost = Math.ceil(rates.energy * timeMod.energy);

    if (task.pillar !== 'Quran' && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        // 3️⃣ Weekly Tracking Updates
        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise
        };

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;
            addToast(`✅ تمت القراءة: ${pagesToAdd} صفحة`, 'success');
        } 
        else {
            newStats.energy = prev.energy - finalEnergyCost;

            let finalXpReward = Math.ceil(rates.xp * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;

            // Weekly XP
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            let didLevelUp = false;

            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                maxXp = Math.floor(100 * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (didLevelUp) setShowLevelUpModal(true);
            else addToast(`+${finalXpReward} XP | -${finalEnergyCost}⚡`, 'success');

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

