  const chartData = rawPillarData.filter(d => d.value > 0);
  const maxVal = Math.max(...rawPillarData.map(d => d.value), 5);
  const strongest = [...rawPillarData].sort((a, b) => b.value - a.value)[0]?.value > 0 ? [...rawPillarData].sort((a, b) => b.value - a.value)[0] : null;

  // --- History Card Component ---
