                    Rank Score: {week.rankScore}
                </div>
            </div>
            <div className="grid grid-cols-3 gap-2 mt-2">
                <div className="bg-black/30 p-2 rounded text-center">
                    <span className="block text-[10px] text-neutral-500">XP</span>
                    <span className="font-bold text-white text-xs">{week.totalXP}</span>
                </div>
                <div className="bg-black/30 p-2 rounded text-center">
                    <span className="block text-[10px] text-neutral-500">Tasks</span>
                    <span className="font-bold text-white text-xs">{week.tasksCompleted}</span>
                </div>
                <div className="bg-black/30 p-2 rounded text-center">
                    <span className="block text-[10px] text-neutral-500">Streak</span>
                    <span className="font-bold text-white text-xs">{week.streakMax}</span>
                </div>
            </div>
        </div>
    );
  };

  return (
    <div className="h-full overflow-y-auto p-4 space-y-6 animate-fade-in pb-24">

      {/* Header with Toggle */}
      <div className="flex items-center justify-between mb-2 px-2">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-game-red/20 rounded-xl border border-game-red/30">
                <PieChartIcon size={24} className="text-game-red" />
            </div>
            <div>
                <h2 className="text-2xl font-black text-white">{t('statistics')}</h2>
                <p className="text-xs text-neutral-400">تحليل أداء الصياد</p>
            </div>
          </div>

          <div className="flex bg-neutral-900 rounded-lg p-1 border border-neutral-800">
             <button 
                onClick={() => setView('current')}
                className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${view === 'current' ? 'bg-neutral-700 text-white' : 'text-neutral-500'}`}
             >
                الحالي
             </button>
             <button 
                onClick={() => setView('history')}
                className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${view === 'history' ? 'bg-neutral-700 text-white' : 'text-neutral-500'}`}
             >
                السجل
             </button>
          </div>
      </div>

      {view === 'current' ? (
        <>
            {/* 1. KPIs Grid */}
            <div className="grid grid-cols-2 gap-3">
                <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-2xl shadow-lg relative overflow-hidden group">
                    <div className="relative z-10">
                        <div className="flex items-center gap-2 mb-2 text-blue-500">
                            <Activity size={16} />
                            <span className="text-[10px] font-bold uppercase tracking-widest">{t('completionRate')}</span>
                        </div>
                        <p className="text-3xl font-black text-white">{completionRate}%</p>
                        <div className="w-full bg-neutral-800 h-1.5 rounded-full mt-2 overflow-hidden">
                            <div className="bg-blue-500 h-full rounded-full transition-all duration-1000" style={{ width: `${completionRate}%` }} />
                        </div>
                    </div>
                </div>

                <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-2xl shadow-lg relative overflow-hidden group">
                    <div className="relative z-10">
                        <div className="flex items-center gap-2 mb-2 text-yellow-500">
                            <Trophy size={16} />
                            <span className="text-[10px] font-bold uppercase tracking-widest">{t('strongestPillar')}</span>
                        </div>
                        <p className="text-lg font-black text-white truncate">
                            {strongest ? strongest.name : '-'}
                        </p>
                        <p className="text-xs text-neutral-500 font-mono mt-1">
                            {strongest ? `${strongest.value} ${t('completed')}` : t('noData')}
                        </p>
                    </div>
                </div>

                <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-2xl shadow-lg">
                    <div className="flex items-center gap-2 mb-2 text-green-500">
                        <Target size={16} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{t('totalTasks')}</span>
                    </div>
                    <div className="flex items-end gap-1">
                        <p className="text-2xl font-black text-white">{completedTasks}</p>
                        <span className="text-xs text-neutral-500 mb-1">/ {totalTasks}</span>
                    </div>
                </div>

                <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-2xl shadow-lg">
                    <div className="flex items-center gap-2 mb-2 text-game-red">
                        <TrendingUp size={16} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{t('level')}</span>
                    </div>
                    <p className="text-2xl font-black text-white">{stats.level}</p>
                </div>
            </div>

            {/* 2. Hunter Radar Chart */}
            <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-3xl shadow-xl relative overflow-hidden">
                <div className="flex items-center justify-between mb-2">
                    <h3 className="text-sm font-bold text-neutral-300 uppercase tracking-widest border-l-4 border-game-red pl-2">
                        {t('hunterStats')}
                    </h3>
                </div>

                <div className="h-64 w-full relative">
                    <ResponsiveContainer width="100%" height="100%">
                        <RadarChart cx="50%" cy="50%" outerRadius="70%" data={rawPillarData}>
                            <PolarGrid stroke="#333" strokeDasharray="3 3" />
                            <PolarAngleAxis 
                                dataKey="name" 
                                tick={{ fill: '#9ca3af', fontSize: 10, fontWeight: 'bold' }} 
                            />
                            <PolarRadiusAxis angle={30} domain={[0, maxVal]} tick={false} axisLine={false} />
                            <Radar
                                name="Tasks"
                                dataKey="value"
                                stroke="#dc2626"
                                strokeWidth={2}
                                fill="#dc2626"
                                fillOpacity={0.4}
                            />
                            <Tooltip 
                                contentStyle={{ backgroundColor: '#000', border: '1px solid #333', borderRadius: '8px', fontSize: '12px' }}
                                itemStyle={{ color: '#fff' }}
                            />
                        </RadarChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* 3. Stats for Current Week (Tracking Preview) */}
            <div className="bg-neutral-900 border border-dashed border-neutral-800 p-4 rounded-2xl">
                 <h3 className="text-xs font-bold text-neutral-500 uppercase mb-3 flex items-center gap-2">
                    <Calendar size={14} /> تتبع الأسبوع الحالي
                 </h3>
                 <div className="flex justify-between items-center bg-black/40 p-3 rounded-xl border border-neutral-800">
                    <div className="text-center">
                        <span className="text-xs text-neutral-500 block">Weekly XP</span>
                        <span className="text-game-red font-black">{stats.weeklyXpAccumulated}</span>
                    </div>
                    <div className="h-6 w-px bg-neutral-800" />
                    <div className="text-center">
                        <span className="text-xs text-neutral-500 block">Tasks</span>
                        <span className="text-white font-black">{stats.weeklyTasksCompleted}</span>
                    </div>
                    <div className="h-6 w-px bg-neutral-800" />
                    <div className="text-center">
                        <span className="text-xs text-neutral-500 block">Max Streak</span>
                        <span className="text-white font-black">{stats.weeklyMaxStreak}</span>
                    </div>
                 </div>
            </div>
        </>
      ) : (
        /* HISTORY VIEW */
        <div className="space-y-4">
            {weeklyHistory.length === 0 ? (
                <div className="text-center py-10 opacity-50">
                    <History size={48} className="mx-auto mb-2" />
                    <p>لا يوجد سجل تاريخي حتى الآن.</p>
                    <p className="text-xs mt-1">يتم إنشاء التقارير تلقائياً نهاية كل أسبوع.</p>
                </div>
            ) : (
                [...weeklyHistory].reverse().map((week) => (
                    <WeeklyCard key={week.weekId} week={week} />
                ))
            )}
        </div>
      )}

    </div>
  );
};

