  return (
    <div className="h-full overflow-y-auto p-4 space-y-6 animate-fade-in pb-24">

      {/* Header with Toggle */}
      <div className="flex items-center justify-between mb-2 px-2">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-game-red/20 rounded-xl border border-game-red/30">
