  const MonthlyReportCard: React.FC<{ report: MonthlyReport, reward?: MonthlyReward }> = ({ report, reward }) => (
    <div className="bg-gradient-to-br from-neutral-900 to-neutral-950 border border-neutral-800 p-5 rounded-2xl mb-4 shadow-xl animate-slide-up relative overflow-hidden">
