        {reward?.badge === 'LEGENDARY' && <div className="absolute -right-10 -top-10 w-40 h-40 bg-yellow-500/20 rounded-full blur-3xl pointer-events-none animate-pulse" />}
        {reward?.badge === 'GOLD' && <div className="absolute -right-10 -top-10 w-40 h-40 bg-orange-500/10 rounded-full blur-3xl pointer-events-none" />}

        <div className="flex justify-between items-start mb-3 relative z-10">
             <div>
                <span className="text-[10px] text-neutral-500 font-bold uppercase block mb-1">
                   {report.monthId}
                </span>
                <div className={`inline-flex items-center gap-1 px-3 py-1.5 rounded-lg border text-sm font-black tracking-wide ${getRatingColor(report.monthRating)}`}>
                    <Trophy size={14} />
                    {t(report.monthRating.toLowerCase() as any)}
                </div>
            </div>

            {/* Monthly Reward Display */}
            {reward && (
                <div className="flex flex-col items-end">
                    <div className="p-2 bg-neutral-950/50 rounded-full border border-neutral-700 shadow-lg mb-1">
                        <BadgeIcon tier={reward.badge} />
                    </div>
                    {reward.xpBonus > 0 && (
                        <span className="text-xs font-black text-yellow-400 drop-shadow-sm">+{reward.xpBonus} XP</span>
                    )}
                </div>
            )}
        </div>

        <p className="text-sm text-neutral-300 leading-relaxed font-medium mb-4 relative z-10">
            "{report.summaryText}"
        </p>

        <div className="bg-black/40 p-3 rounded-xl relative z-10 border border-neutral-800">
             <div className="flex items-center justify-between mb-2">
                <span className="text-[10px] text-neutral-500">Consistency Change</span>
                <div className="flex items-center gap-1 text-xs font-bold text-white">
                    {report.comparison.consistencyChange !== null ? (
                        <>
