interface Props {
  pillarId: PillarType;
  onBack: () => void;
  onAddTask: () => void;
  onEditTask?: (task: Task) => void;
  customHeader?: React.ReactNode; // New Prop
}

export const PillarDetailScreen: React.FC<Props> = ({ pillarId, onBack, onAddTask, onEditTask, customHeader }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();

  const pillarTasks = tasks.filter(t => t.pillar === pillarId);
  const activeTasks = pillarTasks.filter(t => !t.completed);
  const completedTasks = pillarTasks.filter(t => t.completed);

  // Sorting: Newest first
  activeTasks.sort((a, b) => b.createdAt - a.createdAt);

  return (
    <div className="flex flex-col h-full bg-game-black animate-fade-in absolute inset-0 z-30">

      {/* Header Area */}
      <div className="relative">
        <button 
            onClick={onBack}
            className="absolute top-6 left-4 z-20 p-2 bg-black/50 backdrop-blur rounded-full text-white border border-neutral-700 hover:bg-neutral-800"
        >
            <ArrowRight size={20} />
        </button>
        <PillWidget pillarId={pillarId} taskCount={activeTasks.length} variant="header" />
      </div>

      {/* Task List Container */}
      <div className="flex-1 overflow-y-auto pb-24 no-scrollbar">

        {/* Custom Header Injection (Daily Quest) */}
        {customHeader && <div className="mb-2">{customHeader}</div>}

        <div className="px-4 space-y-4">
            {activeTasks.length === 0 && completedTasks.length === 0 && !customHeader && (
                <div className="flex flex-col items-center justify-center h-64 text-neutral-500 opacity-60">
                    <p>لا توجد مهام نشطة</p>
                    <p className="text-xs mt-2">اضغط على + لإضافة مهمة جديدة</p>
                </div>
            )}

            {/* Active Tasks */}
            {activeTasks.map(task => (
                <TaskItem 
                    key={task.id}
                    task={task}
                    onComplete={completeTask}
                    onDelete={deleteTask}
                    onEdit={onEditTask}
                    canAfford={stats.energy >= task.energyCost}
                />
            ))}

            {/* Completed Tasks Header */}
            {completedTasks.length > 0 && (
                <div className="pt-6 border-t border-neutral-900 mt-4">
                    <h4 className="text-xs font-bold text-neutral-600 mb-4 uppercase tracking-widest flex items-center gap-2">
                        <span>المكتملة</span>
                        <span className="bg-neutral-800 text-neutral-500 px-1.5 rounded-md text-[10px]">{completedTasks.length}</span>
                    </h4>
                    {completedTasks.map(task => (
                        <TaskItem 
                            key={task.id}
                            task={task}
                            onComplete={completeTask}
                            onDelete={deleteTask}
                            canAfford={true}
                        />
                    ))}
                </div>
            )}
        </div>
      </div>

      {/* FAB to Add Task */}
      <button 
        onClick={onAddTask}
        className="fixed bottom-8 left-6 bg-white text-black p-4 rounded-full shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:scale-110 transition-transform z-40"
      >
        <Plus size={24} />
      </button>
    </div>
  );
};

