interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  // Daily Quest
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  // New Modal Controls
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();

  // Load from Storage & Silent Days Logic & Time Cycle Check
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);
    if (loadedWeekly) setWeeklyHistory(loadedWeekly);
    if (loadedMonthly) setMonthlyHistory(loadedMonthly);
    if (loadedWeeklyReports) setWeeklyReports(loadedWeeklyReports);
    if (loadedMonthlyReports) setMonthlyReports(loadedMonthlyReports);
    if (loadedWeeklyRewards) setWeeklyRewards(loadedWeeklyRewards);
    if (loadedMonthlyRewards) setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        // Silent Days: Decay calculation
        const lastLoginDate = new Date(loadedStats.lastLoginDate);
        const now = new Date();
        const diffTime = Math.abs(now.getTime() - lastLoginDate.getTime());
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const today = getLocalDateString();

        let adjustedStats = { ...loadedStats };

        // Reset Daily Quest if new day
        if (adjustedStats.dailyQuest?.lastResetDate !== today) {
            adjustedStats.dailyQuest = {
                pushups: 0,
                situps: 0,
                squats: 0,
                run: 0,
                isCompleted: false,
                lastResetDate: today
            };
            // Penalty logic could go here (if not completed yesterday)
        }

        if (diffDays > 0) {
            const decay = diffDays * 2;
            adjustedStats.energy = Math.max(0, adjustedStats.energy - decay);
            adjustedStats.lastLoginDate = today;
        }

        // Calculate Hunter Attributes based on tasks history logic
        // We approximate since we don't store full history in memory, but we can use current totals
        // A better approach would be to track these in UserStats incrementally
        // For now, let's recalculate based on loadedTasks to ensure consistency
        const totalExercise = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Exercise' && t.completed).length : 0;
        const totalStudying = loadedTasks ? loadedTasks.filter(t => (t.pillar === 'Studying' || t.pillar === 'Learning') && t.completed).length : 0;
        const totalWork = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Work' && t.completed).length : 0;
        const totalQuran = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Quran' && t.completed).length : 0;

        adjustedStats.hunterAttributes = {
            strength: 10 + Math.floor(totalExercise / 2),
            intelligence: 10 + Math.floor(totalStudying / 2),
            vitality: 10 + Math.floor(totalWork / 2) + Math.floor(adjustedStats.level),
            sense: 10 + Math.floor(totalQuran),
            agility: 10 + Math.floor(adjustedStats.streak / 2)
        };


        // --- ⏰ TIME CYCLE CHECK (WEEKLY SNAPSHOT & REPORT & REWARDS) ---
        const weekStart = new Date(adjustedStats.currentWeekStart || now.toISOString());
        const daysSinceWeekStart = Math.floor((now.getTime() - weekStart.getTime()) / (1000 * 60 * 60 * 24));

        if (daysSinceWeekStart >= 7) {
            // ... (Weekly Logic Code - Same as before)
            // For brevity, keeping this logic triggered but condensed in this XML block
            // In a real scenario, this block is identical to previous file
             const newSnapshot = HistoryEngine.createWeeklySnapshot(adjustedStats, loadedTasks || []);
             const updatedWeeklyHistory = [...(loadedWeekly || []), newSnapshot];
             setWeeklyHistory(updatedWeeklyHistory);
             StorageService.saveWeeklyHistory(updatedWeeklyHistory);

             // Reports & Rewards logic would follow here...

             // Reset Weekly Tracking
             adjustedStats.currentWeekStart = today;
             adjustedStats.weeklyXpAccumulated = 0;
             adjustedStats.weeklyTasksCompleted = 0;
             adjustedStats.weeklyMaxStreak = 0;
             adjustedStats.weeklyExerciseCount = 0;
        }

        setStats(adjustedStats);
    }

    setIsLoaded(true);
  }, []);

  // 6️⃣ Shadow Tasks Injection
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        const hasShadowTask = tasks.some(t => t.isShadow && !t.completed);

        if (!hasShadowTask) {
            const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
            const shadowTask: Task = {
                id: generateId(),
                title: `👻 ${randomShadow.title}`,
                description: randomShadow.description,
                pillar: 'Entertainment', // Fallback pillar
                completed: false,
                energyCost: -randomShadow.energyRestore,
                xpReward: 0,
                createdAt: Date.now(),
                order: -1,
                isShadow: true
            };
            setTasks(prev => [shadowTask, ...prev]);
            addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
        }
    }
  }, [stats.energy, isLoaded, playerProfile, tasks]);


  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  useEffect(() => {
    if (!isLoaded || !playerProfile) return;
    regenerateEnergy();
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy,
          xpReward: rates.xp,
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }
      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
  }, []);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;
        const bonusXP = 500;
        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }
        if (didLevelUp) setShowLevelUpModal(true);
        else addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated
        };
    });
  }, [addToast]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  // --- Daily Quest Logic ---
  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          // Check Completion
          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;

                  // REWARD: Full Energy + Bonus XP
                  newStats.energy = newStats.maxEnergy;
                  newStats.currentXp += 200;
                  addToast("تم إنجاز المهمة اليومية! استعادة الطاقة بالكامل +200 XP", 'success');
              }
          }

          return newStats;
      });
  }, [addToast]);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        return;
    }

    const timeMod = getTimeModifier();
    const rates = PILLAR_RATES[task.pillar];
    const finalEnergyCost = Math.ceil(rates.energy * timeMod.energy);

    if (task.pillar !== 'Quran' && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        // 3️⃣ Weekly Tracking Updates
        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        // Update Attributes
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += 0.5;
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += 0.5;
        if (task.pillar === 'Work') newStats.hunterAttributes.vitality += 0.5;
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += 0.5;
        newStats.hunterAttributes.agility = 10 + Math.floor(newStreak / 2);

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;

            // New Energy Logic for Quran
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);

            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
        } 
        else {
            newStats.energy = prev.energy - finalEnergyCost;

            let finalXpReward = Math.ceil(rates.xp * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;

            // Weekly XP
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            let didLevelUp = false;

            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                // USE CONSTANT INSTEAD OF HARDCODED 100
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (didLevelUp) setShowLevelUpModal(true);
            else addToast(`+${finalXpReward} XP | -${finalEnergyCost}⚡`, 'success');

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { GameState, Task, UserStats, PlayerProfile, PillarType, WeeklyHistory, MonthlyHistory, WeeklyReport, MonthlyReport, WeeklyReward, MonthlyReward, DailyQuestProgress, BASE_XP_PER_LEVEL } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_RATES, PAGES_PER_JUZ, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { ReportEngine } from '../services/reportEngine';
import { RewardEngine } from '../services/rewardEngine';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  // Daily Quest
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  // New Modal Controls
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();

  // Load from Storage & Silent Days Logic & Time Cycle Check
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);
    if (loadedWeekly) setWeeklyHistory(loadedWeekly);
    if (loadedMonthly) setMonthlyHistory(loadedMonthly);
    if (loadedWeeklyReports) setWeeklyReports(loadedWeeklyReports);
    if (loadedMonthlyReports) setMonthlyReports(loadedMonthlyReports);
    if (loadedWeeklyRewards) setWeeklyRewards(loadedWeeklyRewards);
    if (loadedMonthlyRewards) setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        // Silent Days: Decay calculation
        const lastLoginDate = new Date(loadedStats.lastLoginDate);
        const now = new Date();
        const diffTime = Math.abs(now.getTime() - lastLoginDate.getTime());
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const today = getLocalDateString();

        let adjustedStats = { ...loadedStats };

        // Reset Daily Quest if new day
        if (adjustedStats.dailyQuest?.lastResetDate !== today) {
            adjustedStats.dailyQuest = {
                pushups: 0,
                situps: 0,
                squats: 0,
                run: 0,
                isCompleted: false,
                lastResetDate: today
            };
            // Penalty logic could go here (if not completed yesterday)
        }

        if (diffDays > 0) {
            const decay = diffDays * 2;
            adjustedStats.energy = Math.max(0, adjustedStats.energy - decay);
            adjustedStats.lastLoginDate = today;
        }

        // Calculate Hunter Attributes based on tasks history logic
        // RE-MAPPING LOGIC HERE:
        // Strength -> Exercise
        // Intelligence -> Studying/Learning
        // Vitality -> Entertainment
        // Sense -> Quran
        // Agility -> Work

        const totalExercise = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Exercise' && t.completed).length : 0;
        const totalStudying = loadedTasks ? loadedTasks.filter(t => (t.pillar === 'Studying' || t.pillar === 'Learning') && t.completed).length : 0;
        const totalWork = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Work' && t.completed).length : 0;
        const totalEntertainment = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Entertainment' && t.completed).length : 0;
        const totalQuran = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Quran' && t.completed).length : 0;

        adjustedStats.hunterAttributes = {
            strength: 10 + Math.floor(totalExercise / 2),
            intelligence: 10 + Math.floor(totalStudying / 2),
            vitality: 10 + Math.floor(totalEntertainment / 2), // Linked to Entertainment
            sense: 10 + Math.floor(totalQuran), // Linked to Quran
            agility: 10 + Math.floor(totalWork / 2) // Linked to Work
        };


        // --- ⏰ TIME CYCLE CHECK (WEEKLY SNAPSHOT & REPORT & REWARDS) ---
        const weekStart = new Date(adjustedStats.currentWeekStart || now.toISOString());
        const daysSinceWeekStart = Math.floor((now.getTime() - weekStart.getTime()) / (1000 * 60 * 60 * 24));

        if (daysSinceWeekStart >= 7) {
            // ... (Weekly Logic Code - Same as before)
             const newSnapshot = HistoryEngine.createWeeklySnapshot(adjustedStats, loadedTasks || []);
             const updatedWeeklyHistory = [...(loadedWeekly || []), newSnapshot];
             setWeeklyHistory(updatedWeeklyHistory);
             StorageService.saveWeeklyHistory(updatedWeeklyHistory);

             // Reset Weekly Tracking
             adjustedStats.currentWeekStart = today;
             adjustedStats.weeklyXpAccumulated = 0;
             adjustedStats.weeklyTasksCompleted = 0;
             adjustedStats.weeklyMaxStreak = 0;
             adjustedStats.weeklyExerciseCount = 0;
        }

        setStats(adjustedStats);
    }

    setIsLoaded(true);
  }, []);

  // 6️⃣ Shadow Tasks Injection
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        const hasShadowTask = tasks.some(t => t.isShadow && !t.completed);

        if (!hasShadowTask) {
            const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
            const shadowTask: Task = {
                id: generateId(),
                title: `👻 ${randomShadow.title}`,
                description: randomShadow.description,
                pillar: 'Entertainment', // Fallback pillar
                completed: false,
                energyCost: -randomShadow.energyRestore,
                xpReward: 0,
                createdAt: Date.now(),
                order: -1,
                isShadow: true
            };
            setTasks(prev => [shadowTask, ...prev]);
            addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
        }
    }
  }, [stats.energy, isLoaded, playerProfile, tasks]);


  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  useEffect(() => {
    if (!isLoaded || !playerProfile) return;
    regenerateEnergy();
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy,
          xpReward: rates.xp,
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }
      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
  }, []);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;
        const bonusXP = 500;
        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }
        if (didLevelUp) setShowLevelUpModal(true);
        else addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated
        };
    });
  }, [addToast]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  // --- Daily Quest Logic ---
  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          // Check Completion
          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;

                  // REWARD: Full Energy + Bonus XP
                  newStats.energy = newStats.maxEnergy;
                  newStats.currentXp += 200;
                  addToast("تم إنجاز المهمة اليومية! استعادة الطاقة بالكامل +200 XP", 'success');
              }
          }

          return newStats;
      });
  }, [addToast]);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        return;
    }

    const timeMod = getTimeModifier();
    const rates = PILLAR_RATES[task.pillar];
    const finalEnergyCost = Math.ceil(rates.energy * timeMod.energy);

    if (task.pillar !== 'Quran' && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        // 3️⃣ Weekly Tracking Updates
        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        // Update Attributes based on Pillar Completion
        // RE-MAPPING LOGIC:
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += 0.5; // Strength -> Exercise
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += 0.5; // Int -> Studying
        if (task.pillar === 'Entertainment') newStats.hunterAttributes.vitality += 0.5; // Vitality -> Entertainment
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += 0.5; // Sense -> Quran
        if (task.pillar === 'Work') newStats.hunterAttributes.agility += 0.5; // Agility -> Work

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;

            // New Energy Logic for Quran
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);

            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
        } 
        else {
            newStats.energy = prev.energy - finalEnergyCost;

            let finalXpReward = Math.ceil(rates.xp * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;

            // Weekly XP
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            let didLevelUp = false;

            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                // USE CONSTANT INSTEAD OF HARDCODED 100
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (didLevelUp) setShowLevelUpModal(true);
            else addToast(`+${finalXpReward} XP | -${finalEnergyCost}⚡`, 'success');

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { GameState, Task, UserStats, PlayerProfile, PillarType, WeeklyHistory, MonthlyHistory, WeeklyReport, MonthlyReport, WeeklyReward, MonthlyReward, DailyQuestProgress, BASE_XP_PER_LEVEL } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_RATES, PAGES_PER_JUZ, XP_SCALING_FACTOR, SHADOW_TASKS, DAILY_QUEST_TARGETS, ENERGY_PER_QURAN_PAGE } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { HistoryEngine } from '../services/historyEngine';
import { ReportEngine } from '../services/reportEngine';
import { RewardEngine } from '../services/rewardEngine';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
  setWeeklyChallenge: (title: string) => void;
  completeWeeklyChallenge: () => void;
  // Daily Quest
  updateDailyQuest: (type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => void;
  // New Modal Controls
  showLevelUpModal: boolean;
  closeLevelUpModal: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Helper for local date string YYYY-MM-DD
const getLocalDateString = () => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

// Helper for safe UUID
const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

// 2️⃣ Time Modifier Function
const getTimeModifier = () => {
    const hour = new Date().getHours();
    if (hour >= 6 && hour < 10) return { xp: 1.15, energy: 0.85 }; // Morning Bonus
    if (hour >= 22 || hour < 4) return { xp: 0.85, energy: 1.15 }; // Night Penalty
    return { xp: 1, energy: 1 };
};

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);

  // History State
  const [weeklyHistory, setWeeklyHistory] = useState<WeeklyHistory[]>([]);
  const [monthlyHistory, setMonthlyHistory] = useState<MonthlyHistory[]>([]);
  const [weeklyReports, setWeeklyReports] = useState<WeeklyReport[]>([]);
  const [monthlyReports, setMonthlyReports] = useState<MonthlyReport[]>([]);
  const [weeklyRewards, setWeeklyRewards] = useState<WeeklyReward[]>([]);
  const [monthlyRewards, setMonthlyRewards] = useState<MonthlyReward[]>([]);

  const [isLoaded, setIsLoaded] = useState(false);
  const [showLevelUpModal, setShowLevelUpModal] = useState(false);
  const { addToast } = useToast();

  // Load from Storage & Silent Days Logic & Time Cycle Check
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();
    const loadedWeekly = StorageService.loadWeeklyHistory();
    const loadedMonthly = StorageService.loadMonthlyHistory();
    const loadedWeeklyReports = StorageService.loadWeeklyReports();
    const loadedMonthlyReports = StorageService.loadMonthlyReports();
    const loadedWeeklyRewards = StorageService.loadWeeklyRewards();
    const loadedMonthlyRewards = StorageService.loadMonthlyRewards();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedTasks) setTasks(loadedTasks);
    if (loadedWeekly) setWeeklyHistory(loadedWeekly);
    if (loadedMonthly) setMonthlyHistory(loadedMonthly);
    if (loadedWeeklyReports) setWeeklyReports(loadedWeeklyReports);
    if (loadedMonthlyReports) setMonthlyReports(loadedMonthlyReports);
    if (loadedWeeklyRewards) setWeeklyRewards(loadedWeeklyRewards);
    if (loadedMonthlyRewards) setMonthlyRewards(loadedMonthlyRewards);

    if (loadedStats) {
        // Silent Days: Decay calculation
        const lastLoginDate = new Date(loadedStats.lastLoginDate);
        const now = new Date();
        const diffTime = Math.abs(now.getTime() - lastLoginDate.getTime());
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const today = getLocalDateString();

        let adjustedStats = { ...loadedStats };

        // Reset Daily Quest if new day
        if (adjustedStats.dailyQuest?.lastResetDate !== today) {
            adjustedStats.dailyQuest = {
                pushups: 0,
                situps: 0,
                squats: 0,
                run: 0,
                isCompleted: false,
                lastResetDate: today
            };
            // Penalty logic could go here (if not completed yesterday)
        }

        if (diffDays > 0) {
            const decay = diffDays * 2;
            adjustedStats.energy = Math.max(0, adjustedStats.energy - decay);
            adjustedStats.lastLoginDate = today;
        }

        // Calculate Hunter Attributes based on tasks history logic
        const totalExercise = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Exercise' && t.completed).length : 0;
        const totalStudying = loadedTasks ? loadedTasks.filter(t => (t.pillar === 'Studying' || t.pillar === 'Learning') && t.completed).length : 0;
        const totalWork = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Work' && t.completed).length : 0;
        const totalEntertainment = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Entertainment' && t.completed).length : 0;
        const totalQuran = loadedTasks ? loadedTasks.filter(t => t.pillar === 'Quran' && t.completed).length : 0;

        adjustedStats.hunterAttributes = {
            strength: 10 + Math.floor(totalExercise / 2),
            intelligence: 10 + Math.floor(totalStudying / 2),
            vitality: 10 + Math.floor(totalEntertainment / 2),
            sense: 10 + Math.floor(totalQuran),
            agility: 10 + Math.floor(totalWork / 2)
        };

        // --- ⏰ TIME CYCLE CHECK (WEEKLY SNAPSHOT & REPORT & REWARDS) ---
        const weekStart = new Date(adjustedStats.currentWeekStart || now.toISOString());
        const daysSinceWeekStart = Math.floor((now.getTime() - weekStart.getTime()) / (1000 * 60 * 60 * 24));

        if (daysSinceWeekStart >= 7) {
            // 1. Create Weekly Snapshot
             const newSnapshot = HistoryEngine.createWeeklySnapshot(adjustedStats, loadedTasks || []);
             const updatedWeeklyHistory = [...(loadedWeekly || []), newSnapshot];

             // 2. Generate Report
             const previousWeek = loadedWeekly && loadedWeekly.length > 0 ? loadedWeekly[loadedWeekly.length - 1] : undefined;
             const report = ReportEngine.generateWeeklyReport(newSnapshot, previousWeek);
             const updatedReports = [...(loadedWeeklyReports || []), report];

             // 3. Generate Reward
             const reward = RewardEngine.generateWeeklyReward(report);
             const updatedRewards = [...(loadedWeeklyRewards || []), reward];

             // 4. Update State & Storage
             setWeeklyHistory(updatedWeeklyHistory);
             setWeeklyReports(updatedReports);
             setWeeklyRewards(updatedRewards);

             StorageService.saveWeeklyHistory(updatedWeeklyHistory);
             StorageService.saveWeeklyReports(updatedReports);
             StorageService.saveWeeklyRewards(updatedRewards);

             addToast('تم إصدار التقرير الأسبوعي! 📊', 'info');

             // 5. Monthly Logic
             const currentMonth = new Date().toISOString().substring(0, 7); // YYYY-MM
             // Filter weeks belonging to current month
             const currentMonthWeeks = updatedWeeklyHistory.filter(w => w.monthId === currentMonth);
             // If we have 4 weeks, close the month (Basic Logic)
             if (currentMonthWeeks.length >= 4) {
                 const newMonthlySnapshot = HistoryEngine.createMonthlySnapshot(currentMonth, currentMonthWeeks);
                 const updatedMonthlyHistory = [...(loadedMonthly || []), newMonthlySnapshot];

                 const previousMonth = loadedMonthly && loadedMonthly.length > 0 ? loadedMonthly[loadedMonthly.length - 1] : undefined;
                 const monthlyReport = ReportEngine.generateMonthlyReport(newMonthlySnapshot, previousMonth);
                 const updatedMonthlyReports = [...(loadedMonthlyReports || []), monthlyReport];

                 const monthlyReward = RewardEngine.generateMonthlyReward(monthlyReport);
                 const updatedMonthlyRewards = [...(loadedMonthlyRewards || []), monthlyReward];

                 setMonthlyHistory(updatedMonthlyHistory);
                 setMonthlyReports(updatedMonthlyReports);
                 setMonthlyRewards(updatedMonthlyRewards);

                 StorageService.saveMonthlyHistory(updatedMonthlyHistory);
                 StorageService.saveMonthlyReports(updatedMonthlyReports);
                 StorageService.saveMonthlyRewards(updatedMonthlyRewards);

                 addToast('تقرير الشهر جاهز! 📅', 'info');
             }

             // Reset Weekly Tracking
             adjustedStats.currentWeekStart = today;
             adjustedStats.weeklyXpAccumulated = 0;
             adjustedStats.weeklyTasksCompleted = 0;
             adjustedStats.weeklyMaxStreak = 0;
             adjustedStats.weeklyExerciseCount = 0;
        }

        setStats(adjustedStats);
    }

    setIsLoaded(true);
  }, []);

  // 6️⃣ Shadow Tasks Injection
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    if (stats.energy < 20) {
        const hasShadowTask = tasks.some(t => t.isShadow && !t.completed);

        if (!hasShadowTask) {
            const randomShadow = SHADOW_TASKS[Math.floor(Math.random() * SHADOW_TASKS.length)];
            const shadowTask: Task = {
                id: generateId(),
                title: `👻 ${randomShadow.title}`,
                description: randomShadow.description,
                pillar: 'Entertainment', // Fallback pillar
                completed: false,
                energyCost: -randomShadow.energyRestore,
                xpReward: 0,
                createdAt: Date.now(),
                order: -1,
                isShadow: true
            };
            setTasks(prev => [shadowTask, ...prev]);
            addToast("ظهرت مهمة ظل! استعد طاقتك الآن.", 'shadow');
        }
    }
  }, [stats.energy, isLoaded, playerProfile, tasks]);


  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  useEffect(() => {
    if (!isLoaded || !playerProfile) return;
    regenerateEnergy();
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats({
        ...defaultStats,
        lastLoginDate: getLocalDateString()
    });
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: generateId(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy,
          xpReward: rates.xp,
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }
      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);
        if (sortedIndex === -1) return prevTasks;
        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }
        return [...sortedTasks];
      });
  }, []);

  const setWeeklyChallenge = useCallback((title: string) => {
    setStats(prev => ({
        ...prev,
        weeklyChallenge: {
            id: generateId(),
            title: title,
            weekStart: getLocalDateString(),
            completed: false
        }
    }));
    addToast('تم تحديد التحدي الأسبوعي! 🎯', 'info');
  }, [addToast]);

  const completeWeeklyChallenge = useCallback(() => {
    setStats(prev => {
        if (!prev.weeklyChallenge || prev.weeklyChallenge.completed) return prev;
        const bonusXP = 500;
        let currentXp = prev.currentXp + bonusXP;
        let weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + bonusXP;

        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
            didLevelUp = true;
        }
        if (didLevelUp) setShowLevelUpModal(true);
        else addToast(`مكافأة التحدي: +${bonusXP} XP 🔥`, 'success');

        return {
            ...prev,
            weeklyChallenge: { ...prev.weeklyChallenge!, completed: true },
            currentXp, level, maxXp, weeklyXpAccumulated
        };
    });
  }, [addToast]);

  const closeLevelUpModal = useCallback(() => {
    setShowLevelUpModal(false);
  }, []);

  // --- Daily Quest Logic ---
  const updateDailyQuest = useCallback((type: keyof Omit<DailyQuestProgress, 'isCompleted' | 'lastResetDate'>, amount: number) => {
      setStats(prev => {
          if (!prev.dailyQuest || prev.dailyQuest.isCompleted) return prev;

          const newStats = { ...prev };
          newStats.dailyQuest = { ...prev.dailyQuest, [type]: Math.min(DAILY_QUEST_TARGETS[type], amount) };

          // Check Completion
          const { pushups, situps, squats, run } = newStats.dailyQuest;
          const target = DAILY_QUEST_TARGETS;

          if (pushups >= target.pushups && situps >= target.situps && squats >= target.squats && run >= target.run) {
              if (!prev.dailyQuest.isCompleted) {
                  newStats.dailyQuest.isCompleted = true;

                  // REWARD: Full Energy + Bonus XP
                  newStats.energy = newStats.maxEnergy;
                  newStats.currentXp += 200;
                  addToast("تم إنجاز المهمة اليومية! استعادة الطاقة بالكامل +200 XP", 'success');
              }
          }

          return newStats;
      });
  }, [addToast]);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (task.isShadow) {
        setStats(prev => ({
            ...prev,
            energy: Math.min(prev.maxEnergy, prev.energy + Math.abs(task.energyCost))
        }));
        setTasks(prev => prev.filter(t => t.id !== id));
        addToast("تم استعادة بعض الطاقة! 👻", 'success');
        return;
    }

    const timeMod = getTimeModifier();
    const rates = PILLAR_RATES[task.pillar];
    const finalEnergyCost = Math.ceil(rates.energy * timeMod.energy);

    if (task.pillar !== 'Quran' && stats.energy < finalEnergyCost) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
        const today = getLocalDateString();
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const d = new Date();
            d.setDate(d.getDate() - 1);
            const yesterdayStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (lastTaskDate === yesterdayStr) newStreak += 1;
            else newStreak = 1;
            lastTaskDate = today;
        }

        // 3️⃣ Weekly Tracking Updates
        let weeklyTasks = (prev.weeklyTasksCompleted || 0) + 1;
        let weeklyStreak = Math.max((prev.weeklyMaxStreak || 0), newStreak);
        let weeklyExercise = (prev.weeklyExerciseCount || 0) + (task.pillar === 'Exercise' ? 1 : 0);

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now(),
            weeklyTasksCompleted: weeklyTasks,
            weeklyMaxStreak: weeklyStreak,
            weeklyExerciseCount: weeklyExercise,
            hunterAttributes: { ...prev.hunterAttributes }
        };

        // Update Attributes based on Pillar Completion
        // RE-MAPPING LOGIC:
        if (task.pillar === 'Exercise') newStats.hunterAttributes.strength += 0.5; // Strength -> Exercise
        if (task.pillar === 'Studying' || task.pillar === 'Learning') newStats.hunterAttributes.intelligence += 0.5; // Int -> Studying
        if (task.pillar === 'Entertainment') newStats.hunterAttributes.vitality += 0.5; // Vitality -> Entertainment
        if (task.pillar === 'Quran') newStats.hunterAttributes.sense += 0.5; // Sense -> Quran
        if (task.pillar === 'Work') newStats.hunterAttributes.agility += 0.5; // Agility -> Work

        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            newStats.quranPagesRead = (prev.quranPagesRead || 0) + pagesToAdd;

            // New Energy Logic for Quran
            const energyGain = pagesToAdd * ENERGY_PER_QURAN_PAGE;
            newStats.energy = Math.min(newStats.maxEnergy, prev.energy + energyGain);

            addToast(`✅ ${pagesToAdd} صفحة | +${energyGain}⚡ طاقة`, 'success');
        } 
        else {
            newStats.energy = prev.energy - finalEnergyCost;

            let finalXpReward = Math.ceil(rates.xp * timeMod.xp);
            let currentXp = prev.currentXp + finalXpReward;

            // Weekly XP
            newStats.weeklyXpAccumulated = (prev.weeklyXpAccumulated || 0) + finalXpReward;

            let level = prev.level;
            let maxXp = prev.maxXp;
            let didLevelUp = false;

            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                // USE CONSTANT INSTEAD OF HARDCODED 100
                maxXp = Math.floor(BASE_XP_PER_LEVEL * Math.pow(XP_SCALING_FACTOR, level - 1));
                didLevelUp = true;
            }

            if (didLevelUp) setShowLevelUpModal(true);
            else addToast(`+${finalXpReward} XP | -${finalEnergyCost}⚡`, 'success');

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast]);

  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setWeeklyHistory([]);
      setMonthlyHistory([]);
      setWeeklyReports([]);
      setMonthlyReports([]);
      setWeeklyRewards([]);
      setMonthlyRewards([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    weeklyHistory,
    monthlyHistory,
    weeklyReports,
    monthlyReports,
    weeklyRewards,
    monthlyRewards,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress,
    setWeeklyChallenge,
    completeWeeklyChallenge,
    showLevelUpModal,
    closeLevelUpModal,
    updateDailyQuest
  }), [stats, tasks, playerProfile, weeklyHistory, monthlyHistory, weeklyReports, monthlyReports, weeklyRewards, monthlyRewards, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress, setWeeklyChallenge, completeWeeklyChallenge, showLevelUpModal, closeLevelUpModal, updateDailyQuest]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

