export type PillarType = 'Learning' | 'Studying' | 'Exercise' | 'Work' | 'Entertainment' | 'Quran';

export type DayOfWeek = 'Saturday' | 'Sunday' | 'Monday' | 'Tuesday' | 'Wednesday' | 'Thursday' | 'Friday';

export interface Task {
  id: string;
  title: string;
  description: string;
  pillar: PillarType;
  completed: boolean;
  energyCost: number;
  xpReward: number;
  dueDate?: string;
  day?: DayOfWeek;
  createdAt: number;
  order: number;
  pages?: number; // Specific for Quran
  isShadow?: boolean; // New: For auto-generated recovery tasks
}

export interface PlayerProfile {
  name: string;
  age: number;
  height: number; // cm
  weight: number; // kg
  createdAt: string;
}

export interface WeeklyChallenge {
  id: string;
  title: string; // User written goal
  weekStart: string; // ISO Date of the start of the week
  completed: boolean;
}

// 1️⃣ Weekly Snapshot Structure
export interface WeeklyHistory {
  weekId: string;             // unique UUID
  monthId: string;            // format: YYYY-MM
  weekIndexInMonth: number;   // 1 -> 4 (or 5)
  startDate: string;          // ISO Date
  endDate: string;            // ISO Date

  totalXP: number;
  tasksCompleted: number;
  streakMax: number;

  statsSummary: {
    learning: number;
    studying: number;
    exercise: number;
    work: number;
    entertainment: number;
    quran: number;
  };

  rankScore: number;
  createdAt: number; // Timestamp
}

// 2️⃣ Monthly Snapshot Structure
export interface MonthlyHistory {
  monthId: string;            // YYYY-MM
  startDate: string;          // ISO Date
  endDate: string;            // ISO Date

  weeksIncluded: string[];    // Array of weekIds

  totalXP: number;
  averageXP: number;
  totalTasks: number;

  bestWeekRankScore: number;
  worstWeekRankScore: number;

  statsSummary: {
    learning: number;
    studying: number;
    exercise: number;
    work: number;
    entertainment: number;
    quran: number;
  };

