import React, { useState, useEffect } from 'react';
import { View, Text, Switch, StyleSheet, Platform, ToastAndroid, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useSettings } from '../context/SettingsContext';
import { useTranslation } from 'react-i18next';
import * as NotificationService from '../services/NotificationService';

const SettingsScreen = () => {
  const { settings, updateSettings, toggleNotifications } = useSettings();
  const { t } = useTranslation();
  const [isSwitchOn, setIsSwitchOn] = useState(settings.notificationsEnabled);

  useEffect(() => {
    setIsSwitchOn(settings.notificationsEnabled);
  }, [settings.notificationsEnabled]);

  const handleToggleSwitch = async () => {
    try {
      const success = await toggleNotifications();
      if (success) {
        setIsSwitchOn(prev => !prev); // Optimistic update
        if (settings.notificationsEnabled) {
          showToast(t('notifications_enabled'));
        } else {
          showToast(t('notifications_disabled'));
        }
      } else {
        showToast(t('notifications_permission_denied'));
      }
    } catch (error) {
      console.error("Error toggling notifications:", error);
      showToast(t('notifications_toggle_error'));
    }
  };

  const showToast = (message: string) => {
    if (Platform.OS === 'android') {
      ToastAndroid.show(message, ToastAndroid.SHORT);
    } else {
      Alert.alert(message);
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.settingRow}>
        <Text style={styles.settingLabel}>{t('system_config')}</Text>
        <Switch
          trackColor={{ false: '#767577', true: '#81b0ff' }}
          thumbColor={isSwitchOn ? '#f5dd4b' : '#f4f3f4'}
          ios_backgroundColor="#3e3e3e"
          onValueChange={handleToggleSwitch}
          value={isSwitchOn}
        />
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 20,
    backgroundColor: '#fff',
  },
  settingRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingVertical: 10,
    borderBottomWidth: 1,
    borderBottomColor: '#ccc',
  },
  settingLabel: {
    fontSize: 16,
  },
});

export default SettingsScreen;
```

