                                `}
                            >
                                <p.icon size={20} className={pillar === p.id ? p.color : 'text-neutral-600'} />
                                <span className="text-[10px] font-bold">{p.label}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Day Selector (Chips) */}
                <div>
