import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { PILLARS } from '../constants';
import { Activity, Flame, Trophy, Zap, Settings, CalendarDays, Bot, Target, CheckCircle2, ArrowRight, PieChart, Plus } from 'lucide-react';
import { DashboardWidget } from './DashboardWidget';
import { PillWidget } from './PillWidget';
import { PillarType, AppTab } from '../types';

interface Props {
  onNavigateToPillar: (pillar: PillarType) => void;
  onOpenSettings: () => void;
  onNavigateToTab: (tab: AppTab) => void;
  onQuickAdd: () => void;
}

export const Dashboard: React.FC<Props> = ({ onNavigateToPillar, onOpenSettings, onNavigateToTab, onQuickAdd }) => {
  const { stats, tasks, playerProfile, setWeeklyChallenge, completeWeeklyChallenge } = useGame();
  const { t } = useSettings();

  const [challengeInput, setChallengeInput] = useState('');
  const completedTasksCount = tasks.filter(t => t.completed).length;
  const showChallengeSelector = !stats.weeklyChallenge;

  const handleSetChallenge = (e: React.FormEvent) => {
    e.preventDefault();
    if(challengeInput.trim()) {
        setWeeklyChallenge(challengeInput);
        setChallengeInput('');
    }
  };

  return (
    <div className="h-full overflow-y-auto no-scrollbar space-y-5 pb-24 animate-fade-in bg-game-black">

      {/* Welcome & Header */}
      <div className="px-5 pt-4 flex justify-between items-start">
        <div>
            <p className="text-neutral-500 text-xs font-mono uppercase tracking-widest mb-1">{t('welcomeHunter')}</p>
            <h2 className="text-3xl font-black text-white tracking-tighter">{playerProfile?.name || 'Player'}</h2>
        </div>
        <button onClick={onOpenSettings} className="p-2 bg-neutral-900 rounded-full text-neutral-500 hover:text-white border border-neutral-800">
            <Settings size={20} />
        </button>
      </div>

      {/* 1️⃣ Weekly Challenge Section */}
      <div className="px-4">
        {showChallengeSelector && (
            <div className="bg-gradient-to-r from-neutral-900 to-black border border-neutral-800 p-4 rounded-2xl shadow-lg relative overflow-hidden">
                <div className="absolute top-0 right-0 w-20 h-20 bg-yellow-600/10 rounded-full blur-2xl"></div>
                <div className="flex items-center gap-2 mb-3 text-yellow-500 relative z-10">
                    <Target size={20} />
                    <h3 className="font-bold text-sm uppercase tracking-wider">{t('weeklyChallenge')}</h3>
                </div>
                <p className="text-xs text-neutral-400 mb-4 relative z-10">{t('challengeDesc')} <span className="text-yellow-500 font-bold">+500 XP</span>.</p>

                <form onSubmit={handleSetChallenge} className="flex gap-2 relative z-10">
                    <input 
                        type="text"
                        value={challengeInput}
                        onChange={(e) => setChallengeInput(e.target.value)}
                        placeholder={t('challengePlaceholder')}
                        className="flex-1 bg-black/50 border border-neutral-700 rounded-xl px-4 py-3 text-sm text-white focus:border-game-red outline-none placeholder:text-neutral-600"
                        maxLength={40}
                    />
                    <button 
                        type="submit"
                        disabled={!challengeInput.trim()}
                        className="bg-game-red text-white px-4 rounded-xl font-bold disabled:opacity-50 hover:bg-red-700 transition-colors"
                    >
                        <ArrowRight size={18} />
                    </button>
                </form>
            </div>
        )}

        {/* Active/Completed Challenge */}
        {stats.weeklyChallenge && (
             <div className={`
                p-4 rounded-2xl flex items-center justify-between shadow-lg border relative overflow-hidden
                ${stats.weeklyChallenge.completed 
                    ? 'bg-green-950/30 border-green-900/50' 
                    : 'bg-neutral-900 border-yellow-900/30'}
             `}>
                <div className="relative z-10 flex-1">
                    <div className="flex items-center gap-2 mb-1">
                        <span className={`text-[10px] font-black uppercase tracking-widest ${stats.weeklyChallenge.completed ? 'text-green-500' : 'text-yellow-500'}`}>
                            {stats.weeklyChallenge.completed ? t('missionComplete') : t('activeMission')}
                        </span>
                    </div>
                    <p className={`font-bold text-sm ${stats.weeklyChallenge.completed ? 'text-neutral-400 line-through' : 'text-white'}`}>
                        {stats.weeklyChallenge.title}
                    </p>
                </div>

                {!stats.weeklyChallenge.completed ? (
                    <button 
                        onClick={completeWeeklyChallenge}
                        className="relative z-10 bg-neutral-800 hover:bg-yellow-600 hover:text-black text-neutral-400 p-3 rounded-xl transition-all border border-neutral-700 hover:border-yellow-500 hover:shadow-[0_0_15px_rgba(234,179,8,0.4)]"
                    >
                        <CheckCircle2 size={24} />
                    </button>
                ) : (
                    <div className="bg-green-500/20 p-2 rounded-full text-green-500">
                        <CheckCircle2 size={24} />
                    </div>
                )}
             </div>
        )}
      </div>

      {/* Stats Grid */}
      <div className="px-4 grid grid-cols-2 gap-3">
        {/* Level Widget (Tall) */}
        <div className="col-span-1 row-span-2">
             <DashboardWidget 
                label={t('level')}
                value={stats.level}
                subValue={t('currentRank')}
                icon={Trophy}
                iconColor="text-yellow-500"
                progress={{
                    current: stats.currentXp,
                    max: stats.maxXp,
                    colorClass: "bg-game-red"
                }}
                variant="circular"
                borderColor="border-game-red/30"
            />
        </div>

        {/* Energy Widget */}
        <DashboardWidget 
            label={t('energy')}
            value={stats.energy}
            subValue={`/ ${stats.maxEnergy}`}
            icon={Zap}
            iconColor="text-blue-400"
            progress={{
                current: stats.energy,
                max: stats.maxEnergy,
                colorClass: "bg-blue-500"
            }}
        />

        {/* Mini Widgets */}
        <div className="grid grid-cols-2 gap-3">
            <DashboardWidget 
                label={t('streak')}
                value={stats.streak}
                icon={Flame}
                iconColor="text-orange-500"
            />
             <DashboardWidget 
                label={t('done')}
                value={completedTasksCount}
                icon={Activity}
                iconColor="text-emerald-500"
            />
        </div>
      </div>

      {/* Quick Nav */}
      <div className="px-4">
          <div className="bg-neutral-900 border border-neutral-800 rounded-2xl p-1 flex">
             <button onClick={() => onNavigateToTab(AppTab.PLANNER)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <CalendarDays size={20} className="text-neutral-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('planner')}</span>
             </button>
             <div className="w-px bg-neutral-800 my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.COACH)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <Bot size={20} className="text-blue-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('coach')}</span>
             </button>
             <div className="w-px bg-neutral-800 my-2"></div>
             <button onClick={() => onNavigateToTab(AppTab.STATS)} className="flex-1 py-3 flex flex-col items-center gap-1 hover:bg-neutral-800 rounded-xl transition-colors">
                <PieChart size={20} className="text-purple-400" />
                <span className="text-[10px] font-bold text-neutral-500">{t('stats')}</span>
             </button>
          </div>
      </div>

      {/* Pillars Preview List (Compact) */}
      <div className="px-4 pb-4 space-y-3">
         <div className="flex justify-between items-end border-b border-neutral-800 pb-2 mb-2">
            <h3 className="text-sm font-black text-neutral-300 uppercase tracking-widest">{t('lifePillars')}</h3>
            <button onClick={() => onNavigateToTab(AppTab.PILLARS)} className="text-xs text-game-red font-bold hover:underline">{t('viewAll')}</button>
         </div>

         <div className="grid grid-cols-1 gap-3">
            {/* Show only top 3 active or prioritized pillars to save space? Or all compacted. */}
            {PILLARS.slice(0, 3).map((pillar) => {
                const count = tasks.filter(t => t.pillar === pillar.id && !t.completed).length;
                return (
                    <PillWidget 
                        key={pillar.id}
                        pillarId={pillar.id} 
                        taskCount={count}
                        onClick={() => onNavigateToPillar(pillar.id)}
                        variant="card"
                    />
                );
            })}
         </div>
      </div>

      {/* Quick Add FAB */}
      <button 
        onClick={onQuickAdd}
        className="fixed bottom-24 left-6 w-14 h-14 bg-white text-black rounded-full shadow-[0_0_30px_rgba(255,255,255,0.3)] flex items-center justify-center hover:scale-110 active:scale-90 transition-all z-40 border-4 border-neutral-200"
      >
        <Plus size={28} strokeWidth={3} />
      </button>

    </div>
  );
};

import React from 'react';
import { PILLARS } from '../constants';
import { PillarType } from '../types';
import { ChevronLeft, CheckCircle2 } from 'lucide-react';
import { useSettings } from '../context/SettingsContext';
import { useGame } from '../context/GameContext';

interface Props {
  pillarId: PillarType;
  taskCount: number;
  onClick?: () => void;
  variant?: 'card' | 'header'; 
}

export const PillWidget: React.FC<Props> = ({ pillarId, taskCount, onClick, variant = 'card' }) => {
  const pillar = PILLARS.find(p => p.id === pillarId);
  const { t, language } = useSettings();
  const { tasks } = useGame();

  if (!pillar) return null;

  const isCard = variant === 'card';
  const colorName = pillar.color.split('-')[1]; // e.g., 'blue', 'green'

  // Dynamic Backgrounds based on variant
  const cardClasses = `
    relative overflow-hidden w-full text-right transition-all duration-300 group
    bg-gradient-to-br from-neutral-900 via-black to-black
    border border-neutral-800 rounded-2xl p-5
    hover:border-${colorName}-500/50 hover:shadow-[0_0_20px_rgba(0,0,0,0.5)] hover:scale-[1.01] active:scale-[0.99]
  `;

  const headerClasses = `
    relative w-full bg-gradient-to-b from-neutral-900 to-game-black
    border-b border-neutral-800 p-6 pb-12 pt-16
  `;

  // Calculate stats for this pillar
  const pillarTasks = tasks.filter(t => t.pillar === pillarId);
  const totalTasks = pillarTasks.length;
  const completedTasks = pillarTasks.filter(t => t.completed).length;
  const progress = totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0;

  // Translation key based on ID
  const translatedLabel = t(pillar.id.toLowerCase() as any);

  return (
    <button 
      onClick={onClick}
      disabled={!onClick}
      className={isCard ? cardClasses : headerClasses}
    >
      {/* Decorative Background Blob */}
      <div className={`absolute top-0 right-0 w-32 h-32 bg-${colorName}-600/10 rounded-full blur-[40px] -translate-y-1/2 translate-x-1/2`} />

      {/* Giant Icon Watermark */}
      <div className={`absolute ${isCard ? '-left-4 -bottom-4 opacity-5 rotate-12 group-hover:opacity-10' : 'left-4 top-1/2 -translate-y-1/2 opacity-5 scale-150'} transition-all duration-500`}>
        <pillar.icon size={isCard ? 100 : 140} />
      </div>

      <div className="relative z-10 flex items-center justify-between w-full">
        <div className="flex items-center gap-4 w-full">
            {/* Icon Container */}
            <div className={`
                flex items-center justify-center rounded-2xl shadow-lg transition-transform duration-300 group-hover:rotate-6
                ${isCard ? 'p-3 w-14 h-14' : 'p-4 w-16 h-16'}
                bg-neutral-900/50 backdrop-blur-md border border-neutral-700/50 ${pillar.color}
                shadow-[0_4px_20px_rgba(0,0,0,0.3)]
            `}>
                <pillar.icon size={isCard ? 28 : 32} />
            </div>

            {/* Text & Stats */}
            <div className="flex-1">
                <h3 className={`font-black text-white leading-tight uppercase tracking-tight ${isCard ? 'text-xl' : 'text-3xl mb-1'}`}>
                    {translatedLabel}
                </h3>

                {isCard && (
                    <div className="flex items-center gap-3 mt-1">
                        {taskCount > 0 ? (
                            <span className="text-xs font-bold text-white bg-red-600/20 text-red-400 px-2 py-0.5 rounded border border-red-900/30">
                                {taskCount} {t('active')}
                            </span>
                        ) : (
                            <span className="text-xs font-medium text-neutral-500">{t('noTasks')}</span>
                        )}
                        {totalTasks > 0 && (
                            <span className="text-[10px] text-neutral-600 font-mono">
                                {t('total')}: {totalTasks}
                            </span>
                        )}
                    </div>
                )}

                {!isCard && (
                    <div className="flex items-center gap-2 text-neutral-400 text-sm font-medium">
                        <span>{t('lvl')} {Math.floor(completedTasks / 10) + 1}</span>
                        <span className="w-1 h-1 bg-neutral-600 rounded-full"></span>
                        <span>{progress.toFixed(0)}% {t('completed')}</span>
                    </div>
                )}
            </div>
        </div>

        {/* Navigation Arrow (Card Only) */}
        {isCard && (
            <div className={`
                p-2 rounded-full border border-neutral-800 bg-neutral-900/50 text-neutral-500
                group-hover:bg-neutral-800 group-hover:text-white group-hover:border-neutral-600 transition-all
                ${language === 'en' ? 'rotate-180' : ''}
            `}>
                <ChevronLeft size={20} />
            </div>
        )}
      </div>

      {/* Progress Bar (Visual Flair) */}
      <div className="absolute bottom-0 left-0 w-full h-1 bg-neutral-800/50">
        <div 
            className={`h-full bg-${colorName}-500 transition-all duration-700 ease-out`} 
            style={{ width: `${progress}%` }} 
        />
      </div>
    </button>
  );
};

import React from 'react';
import { PillarType, Task } from '../types';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { PillWidget } from './PillWidget';
import { TaskItem } from './TaskItem';
import { ArrowRight, Plus, ClipboardList } from 'lucide-react';

interface Props {
  pillarId: PillarType;
  onBack: () => void;
  onAddTask: () => void;
  onEditTask?: (task: Task) => void;
  customHeader?: React.ReactNode; 
}

export const PillarDetailScreen: React.FC<Props> = ({ pillarId, onBack, onAddTask, onEditTask, customHeader }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();
  const { t } = useSettings();

  const pillarTasks = tasks.filter(t => t.pillar === pillarId);
  const activeTasks = pillarTasks.filter(t => !t.completed);
  const completedTasks = pillarTasks.filter(t => t.completed);

  // Sorting: Newest first
  activeTasks.sort((a, b) => b.createdAt - a.createdAt);

  return (
    <div className="flex flex-col h-full bg-game-black animate-fade-in absolute inset-0 z-30">

      {/* Header Area */}
      <div className="relative shadow-2xl z-10">
        <button 
            onClick={onBack}
            className="absolute top-6 left-4 z-20 p-2 bg-black/40 backdrop-blur-md rounded-full text-white border border-white/10 hover:bg-white/10 active:scale-90 transition-all"
        >
            <ArrowRight size={20} />
        </button>
        <PillWidget pillarId={pillarId} taskCount={activeTasks.length} variant="header" />
      </div>

      {/* Task List Container */}
      <div className="flex-1 overflow-y-auto pb-28 pt-4 px-4 no-scrollbar">

        {/* Custom Header Injection (Daily Quest) */}
        {customHeader && <div className="mb-4 animate-slide-up">{customHeader}</div>}

        <div className="space-y-4">
            {activeTasks.length === 0 && completedTasks.length === 0 && !customHeader && (
                <div className="flex flex-col items-center justify-center h-64 text-neutral-600 opacity-80 animate-fade-in">
                    <div className="w-20 h-20 bg-neutral-900 rounded-full flex items-center justify-center mb-4 border border-neutral-800">
                        <ClipboardList size={32} />
                    </div>
                    <p className="font-bold">{t('noTasks')}</p>
                    <p className="text-xs mt-2 text-neutral-500">{t('pillarQuiet')}</p>
                </div>
            )}

            {/* Active Tasks */}
            <div className="space-y-3">
                {activeTasks.map((task, index) => (
                    <div key={task.id} className="animate-slide-up" style={{ animationDelay: `${index * 0.05}s` }}>
                        <TaskItem 
                            task={task}
                            onComplete={completeTask}
                            onDelete={deleteTask}
                            onEdit={onEditTask}
                            canAfford={stats.energy >= task.energyCost}
                        />
                    </div>
                ))}
            </div>

            {/* Completed Tasks Header */}
            {completedTasks.length > 0 && (
                <div className="pt-8 mt-4 border-t border-dashed border-neutral-800/50">
                    <h4 className="text-[10px] font-black text-neutral-600 mb-4 uppercase tracking-[0.2em] flex items-center gap-2">
                        <span>{t('completedArchive')}</span>
                        <span className="bg-neutral-800 text-neutral-400 px-2 py-0.5 rounded-full">{completedTasks.length}</span>
                    </h4>
                    <div className="space-y-2 opacity-60 hover:opacity-100 transition-opacity duration-500">
                        {completedTasks.map(task => (
                            <TaskItem 
                                key={task.id}
                                task={task}
                                onComplete={completeTask}
                                onDelete={deleteTask}
                                canAfford={true}
                            />
                        ))}
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* FAB to Add Task */}
      <button 
        onClick={onAddTask}
        className="fixed bottom-8 left-6 w-14 h-14 bg-white text-black rounded-full shadow-[0_0_30px_rgba(255,255,255,0.2)] hover:scale-110 active:scale-90 transition-all z-40 flex items-center justify-center border-4 border-neutral-200"
      >
        <Plus size={28} strokeWidth={3} />
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target, Calendar, Scroll, CheckCircle2, LayoutGrid, Clock, BarChart3 } from 'lucide-react';
import { PillarType, Task, DayOfWeek, TaskDifficulty } from '../types';
import { PILLARS, HOME_EXERCISES, DAYS_OF_WEEK, PILLAR_BASE_RATES, DIFFICULTY_CONFIG } from '../constants';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
  defaultDay?: DayOfWeek;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar, defaultDay }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [day, setDay] = useState<DayOfWeek>('Saturday');
  const [difficulty, setDifficulty] = useState<TaskDifficulty>('D'); // Default D-Rank
  const [dueDate, setDueDate] = useState('');
  const [pages, setPages] = useState<number>(1); // For Quran

  const { t } = useSettings();

  // Dynamic Calculation
  const baseRates = PILLAR_BASE_RATES[pillar];
  const multiplier = DIFFICULTY_CONFIG[difficulty].multiplier;

  // Calculate final costs
  const calculatedEnergy = Math.ceil(baseRates.energy * multiplier);
  const calculatedXp = Math.ceil(baseRates.xp * multiplier);

  // Get current real day for visual comparison
  const days: DayOfWeek[] = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const todayName = days[new Date().getDay()];

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setDay(initialData.day || 'Saturday');
        setDifficulty(initialData.difficulty || 'D');
        setDueDate(initialData.dueDate || '');
        setPages(initialData.pages || 1);
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        setDay(defaultDay || todayName);
        setDifficulty('D');
        setDueDate('');
        setPages(1);
      }
    }
  }, [isOpen, initialData, defaultPillar, defaultDay, todayName]);

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    setTitle(ex.name);
    setPillar('Exercise');
    setDescription(`Goal: ${ex.reps || ex.duration}`);
    setDifficulty(ex.difficulty);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // For Quran, title can be auto-generated if empty
    let finalTitle = title;
    if (pillar === 'Quran' && !finalTitle.trim()) {
        finalTitle = `${t('quran')} - ${pages} ${t('pagesToRead')}`; // Simplified title generation
    }

    if (!finalTitle.trim()) return;

    if (day === 'Friday' && pillar !== 'Quran') {
        alert(t('fridayRestWarning'));
        return;
    }

    onSubmit({
      title: finalTitle,
      description,
      pillar,
      day,
      difficulty,
      dueDate,
      pages: pillar === 'Quran' ? Number(pages) : undefined
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-700 w-full max-w-md rounded-3xl p-0 relative shadow-2xl max-h-[90vh] overflow-hidden flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-neutral-800 bg-neutral-900 flex justify-between items-center sticky top-0 z-10">
             <h3 className="text-lg font-black text-white uppercase tracking-wider flex items-center gap-2">
                {initialData ? <><CheckCircle2 size={20} className="text-blue-500"/> {t('editTask')}</> : <><LayoutGrid size={20} className="text-game-red"/> {t('newTask')}</>}
            </h3>
            <button onClick={onClose} className="p-2 bg-neutral-800 rounded-full text-neutral-400 hover:text-white hover:bg-neutral-700 transition-colors">
                <X size={20} />
            </button>
        </div>

        <div className="overflow-y-auto p-6 space-y-6 no-scrollbar">
            <form onSubmit={handleSubmit} className="space-y-6">

                {/* Pillar Selector (Grid) */}
                <div>
                    <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest mb-3 block">{t('selectPillar')}</label>
                    <div className="grid grid-cols-3 gap-2">
                        {PILLARS.map(p => (
                            <button
                                key={p.id}
                                type="button"
                                onClick={() => setPillar(p.id)}
                                className={`
                                    flex flex-col items-center justify-center gap-1 p-2 rounded-xl border-2 transition-all
                                    ${pillar === p.id 
                                        ? `bg-${p.color.split('-')[1]}-900/20 border-${p.color.split('-')[1]}-500 text-white shadow-lg shadow-${p.color.split('-')[1]}-500/10` 
                                        : 'bg-neutral-950 border-neutral-800 text-neutral-500 hover:border-neutral-700 hover:bg-neutral-900'}
                                `}
                            >
                                <p.icon size={20} className={pillar === p.id ? p.color : 'text-neutral-600'} />
                                <span className="text-[10px] font-bold">{t(p.id.toLowerCase() as any)}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Day Selector */}
                <div>
                    <div className="flex items-center justify-between mb-3">
                        <label className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest flex items-center gap-2">
                            <Calendar size={12} /> {t('timing')}
                        </label>
                        <div className="flex items-center gap-1 text-[10px] text-game-red font-bold animate-pulse">
                            <Clock size={10} />
                            <span>{t('today')}: {todayName}</span>
                        </div>
                    </div>
                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                        {DAYS_OF_WEEK.map(d => {
                            const isToday = d.id === todayName;
                            return (
                                <button
                                    key={d.id}
                                    type="button"
                                    onClick={() => setDay(d.id)}
                                    className={`
                                        relative flex items-center justify-center px-3 py-2 rounded-lg text-[10px] font-bold border transition-all whitespace-nowrap
                                        ${d.id === 'Friday' && pillar !== 'Quran' ? 'opacity-40 border-dashed border-neutral-800 cursor-not-allowed' : ''}
                                        ${day === d.id 
                                            ? 'bg-white text-black border-white shadow-lg scale-105' 
                                            : isToday ? 'bg-neutral-800 border-game-red text-white' : 'bg-black text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                                    `}
                                    disabled={d.id === 'Friday' && pillar !== 'Quran'}
                                >
                                    {d.label}
                                    {isToday && day !== d.id && (
                                        <span className="absolute -top-1 -right-1 w-2 h-2 bg-game-red rounded-full" />
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Inputs Area */}
                <div className="bg-neutral-950/50 p-4 rounded-2xl border border-neutral-800/50 space-y-4">
                    {pillar === 'Quran' ? (
                        <div className="bg-emerald-900/10 border border-emerald-900/50 p-4 rounded-xl text-center">
                            <label className="block text-xs text-emerald-400 mb-3 font-bold flex items-center justify-center gap-2">
                                <Scroll size={16} /> {t('pagesToRead')}
                            </label>
                            <div className="flex items-center justify-center gap-4">
                                <button type="button" onClick={() => setPages(p => Math.max(1, p - 1))} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">-</button>
                                <span className="text-3xl font-black text-white w-16 text-center">{pages}</span>
                                <button type="button" onClick={() => setPages(p => p + 1)} className="w-10 h-10 rounded-full bg-neutral-800 hover:bg-neutral-700 text-white font-bold text-xl transition-colors">+</button>
                            </div>
                            <p className="text-[10px] text-neutral-500 mt-3">{t('pageEnergy')}</p>
                        </div>
                    ) : (
                        <>
                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('taskTitle')}</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-4 text-white placeholder:text-neutral-700 focus:border-game-red focus:ring-1 focus:ring-game-red outline-none transition-all font-bold"
                                    placeholder={pillar === 'Exercise' ? "..." : t('taskPlaceholder')}
                                />
                            </div>

                            {/* Difficulty Selector */}
                            <div>
                                <label className="text-[10px] text-neutral-500 font-bold mb-2 uppercase flex items-center gap-2">
                                    <BarChart3 size={12} /> {t('difficultyLevel')}
                                </label>
                                <div className="grid grid-cols-6 gap-1">
                                    {(Object.keys(DIFFICULTY_CONFIG) as TaskDifficulty[]).map(key => (
                                        <button
                                            key={key}
                                            type="button"
                                            onClick={() => setDifficulty(key)}
                                            className={`
                                                flex flex-col items-center justify-center py-2 rounded-lg border transition-all
                                                ${difficulty === key 
                                                    ? `bg-neutral-800 border-white text-white` 
                                                    : 'bg-black border-neutral-800 text-neutral-600 hover:border-neutral-600'}
                                            `}
                                        >
                                            <span className={`text-xs font-black ${DIFFICULTY_CONFIG[key].color}`}>{key}</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="text-center mt-2 text-[10px] text-neutral-500 font-mono uppercase">
                                    {DIFFICULTY_CONFIG[difficulty].label} • x{DIFFICULTY_CONFIG[difficulty].multiplier} Rewards
                                </div>
                            </div>

                            {/* Exercise Quick Presets */}
                            {pillar === 'Exercise' && (
                                <div>
                                    <label className="block text-[10px] text-green-500 font-bold mb-2 uppercase tracking-wide">{t('suggestedExercises')}</label>
                                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                                        {HOME_EXERCISES.slice(0, 5).map(ex => (
                                            <button
                                                key={ex.id}
                                                type="button"
                                                onClick={() => handleExerciseSelect(ex)}
                                                className="bg-neutral-900 border border-neutral-800 hover:border-green-500/50 hover:bg-green-900/10 rounded-lg px-3 py-2 whitespace-nowrap transition-colors"
                                            >
                                                <span className="text-xs text-white font-bold">{ex.name.split('/')[1] || ex.name}</span>
                                                <span className="block text-[9px] text-neutral-500">{ex.reps || ex.duration} • Rank {ex.difficulty}</span>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div>
                                <label className="block text-[10px] text-neutral-500 font-bold mb-1 uppercase">{t('additionalNotes')}</label>
                                <textarea 
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    className="w-full bg-black border border-neutral-800 rounded-xl p-3 text-white placeholder:text-neutral-700 focus:border-game-red outline-none h-20 text-sm resize-none"
                                    placeholder={t('detailsPlaceholder')}
                                />
                            </div>
                        </>
                    )}
                </div>

                {/* Stats Preview */}
                {pillar !== 'Quran' && (
                    <div className="flex gap-3">
                        <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                            <div className="bg-yellow-900/20 p-2 rounded-lg text-yellow-500"><Zap size={18} /></div>
                            <div>
                                <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energy')}</p>
                                <p className={`text-lg font-black ${calculatedEnergy < 0 ? 'text-green-500' : 'text-white'}`}>
                                    {calculatedEnergy > 0 ? `-${calculatedEnergy}` : `+${Math.abs(calculatedEnergy)}`}
                                </p>
                            </div>
                        </div>
                        <div className="flex-1 bg-black p-3 rounded-xl border border-neutral-800 flex items-center gap-3">
                            <div className="bg-red-900/20 p-2 rounded-lg text-game-red"><Trophy size={18} /></div>
                            <div>
                                <p className="text-[10px] text-neutral-500 font-bold uppercase">{t('energyReward')}</p>
                                <p className="text-lg font-black text-white">{calculatedXp} XP</p>
                            </div>
                        </div>
                    </div>
                )}

                {/* Submit Button */}
                <button 
                    type="submit" 
                    disabled={day === 'Friday' && pillar !== 'Quran'}
                    className={`
                        w-full font-black py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2
                        ${day === 'Friday' && pillar !== 'Quran' 
                            ? 'bg-neutral-800 text-neutral-500 cursor-not-allowed' 
                            : 'bg-white text-black hover:bg-neutral-200 hover:scale-[1.02] active:scale-[0.98]'}
                    `}
                >
                    {initialData ? t('saveChanges') : t('addToSchedule')}
                </button>

            </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { DAYS_OF_WEEK } from '../constants';
import { TaskItem } from './TaskItem';
import { DayOfWeek, Task } from '../types';
import { Calendar, CheckCircle2, Coffee, Plus } from 'lucide-react';
import { CircularProgress } from './CircularProgress';

interface Props {
  onAddTask: (day: DayOfWeek) => void;
  onEditTask: (task: Task) => void;
}

export const WeeklyPlanner: React.FC<Props> = ({ onAddTask, onEditTask }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();
  const { t } = useSettings();

  // State to track expanded days (default to today or Saturday)
  const [expandedDay, setExpandedDay] = useState<DayOfWeek | null>('Saturday');

  // Optimize: Group tasks by day once using useMemo instead of filtering 7 times inside map
  const tasksByDay = useMemo(() => {
    const grouped: Record<string, Task[]> = {};
    DAYS_OF_WEEK.forEach(d => grouped[d.id] = []);

    tasks.forEach(task => {
        if (task.day && grouped[task.day]) {
            grouped[task.day].push(task);
        }
    });
    return grouped;
  }, [tasks]);

  return (
    <div className="h-full overflow-y-auto pb-24 animate-fade-in p-4 space-y-4 no-scrollbar">
        <div className="flex items-center gap-2 mb-2">
            <Calendar className="text-game-red" size={24} />
            <h2 className="text-2xl font-black text-white">{t('weeklyPlanner')}</h2>
        </div>

        {DAYS_OF_WEEK.map((day) => {
            const isRestDay = day.id === 'Friday';
            const dayTasks = tasksByDay[day.id] || [];
            const completedCount = dayTasks.filter(t => t.completed).length;
            const totalCount = dayTasks.length;
            const progress = totalCount > 0 ? (completedCount / totalCount) * 100 : 0;
            const isExpanded = expandedDay === day.id;

            return (
                <div 
                    key={day.id} 
                    className={`
                        border rounded-2xl overflow-hidden transition-all duration-300
                        ${isRestDay 
                            ? 'bg-gradient-to-br from-emerald-900/20 to-neutral-900 border-emerald-900/50' 
                            : 'bg-neutral-900 border-neutral-800'}
                    `}
                >
                    {/* Header Card */}
                    <div 
                        onClick={() => setExpandedDay(isExpanded ? null : day.id)}
                        className="p-4 flex items-center justify-between cursor-pointer active:bg-white/5"
                    >
                        <div className="flex items-center gap-4">
                            {/* Day Icon / Progress */}
                            <div className="relative w-12 h-12 flex items-center justify-center">
                                {isRestDay ? (
                                    <Coffee className="text-emerald-500" size={24} />
                                ) : (
                                    <CircularProgress 
                                        size={48} 
                                        strokeWidth={4} 
                                        percentage={progress} 
                                        color={progress === 100 ? 'text-game-red' : 'text-neutral-600'}
                                    >
                                        <span className={`text-xs font-bold ${progress === 100 ? 'text-game-red' : 'text-neutral-500'}`}>
                                            {Math.round(progress)}%
                                        </span>
                                    </CircularProgress>
                                )}
                            </div>

                            <div>
                                <h3 className={`font-black text-lg ${isRestDay ? 'text-emerald-500' : 'text-white'}`}>
                                    {day.label}
                                </h3>
                                <p className="text-xs text-neutral-500">
                                    {isRestDay ? t('restDay') : `${completedCount} / ${totalCount} ${t('completedTasks')}`}
                                </p>
                            </div>
                        </div>

                        {/* Expand Icon */}
                        <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''} text-neutral-500`}>
                            ▼
                        </div>
                    </div>

                    {/* Expanded Content */}
                    <div className={`transition-all duration-300 overflow-hidden ${isExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
                        <div className="p-4 pt-0 border-t border-neutral-800/50">

                            {isRestDay ? (
                                <div className="py-6 text-center text-emerald-500/80">
                                    <p className="text-sm font-bold">{t('enjoyDay')}</p>
                                </div>
                            ) : (
                                <>
                                    {dayTasks.length === 0 ? (
                                        <div className="py-8 text-center">
                                            <p className="text-neutral-600 text-sm mb-3">{t('noScheduledTasks')}</p>
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onAddTask(day.id); }}
                                                className="text-game-red text-xs font-bold border border-game-red/30 px-3 py-1.5 rounded-lg hover:bg-game-red/10"
                                            >
                                                + {t('addTaskFor')} {day.label}
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="space-y-3 mt-4">
                                            {dayTasks.map(task => (
                                                <TaskItem 
                                                    key={task.id}
                                                    task={task}
                                                    onComplete={completeTask}
                                                    onDelete={deleteTask}
                                                    onEdit={onEditTask}
                                                    canAfford={stats.energy >= task.energyCost}
                                                />
                                            ))}
                                            <button 
                                                onClick={() => onAddTask(day.id)}
                                                className="w-full py-3 border border-dashed border-neutral-800 rounded-xl text-neutral-600 text-sm font-bold hover:text-white hover:border-neutral-600 transition-colors flex items-center justify-center gap-2"
                                            >
                                                <Plus size={16} /> {t('addMore')}
                                            </button>
                                        </div>
                                    )}
                                </>
                            )}
                        </div>
                    </div>
                </div>
            );
        })}
    </div>
  );
};

import React, { useState } from 'react';
